// src/api/services/orders/OrderServiceFactory.ts
var OrderServiceFactory = class {
  static getService(type) {
    switch (type) {
      case "DINE_IN":
        return new DineInService();
      case "TAKEAWAY":
        return new TakeawayService();
      case "DELIVERY":
        return new DeliveryService();
      case "RESERVATION":
        return new ReservationService();
      default:
        throw new Error(`Unsupported order type: ${type}`);
    }
  }
};

