// src/shared/utils/dateUtils.ts
init_prisma();
async function toUTCRange(restaurantId, businessDate) {
  const restaurant = await prisma.restaurants.findUnique({
    where: { id: restaurantId },
    select: { timezone: true }
  });
  const tz = restaurant?.timezone || "Asia/Karachi";
  const toUTC = (localStr, timeZone, endOfDay = false) => {
    const d = /* @__PURE__ */ new Date(localStr + (endOfDay ? "T23:59:59.999" : "T00:00:00"));
    const localeStr = d.toLocaleString("en-US", { timeZone });
    const diff = d.getTime() - new Date(localeStr).getTime();
    return new Date(d.getTime() + diff);
  };
  return {
    start: toUTC(businessDate, tz, false),
    end: toUTC(businessDate, tz, true)
  };
}

