  /**
   * Get Customer Intelligence (LTV, Frequency, Aura Score)
   */
  async getCustomerIntelligence(restaurantId) {
    const customers = await prisma.customers.findMany({
      where: { restaurant_id: restaurantId },
      include: {
        orders: {
          where: { status: "CLOSED" },
          select: { total: true, created_at: true }
        }
      }
    });
    return customers.map((c) => {
      const totalSpend = c.orders.reduce((sum, o) => sum + Number(o.total), 0);
      const orderCount = c.orders.length;
      const lastOrder = c.orders.length > 0 ? [...c.orders].sort((a, b) => b.created_at.getTime() - a.created_at.getTime())[0].created_at : null;
      const frequencyScore = Math.min(orderCount * 8, 50);
      const spendScore = Math.min(totalSpend / 2e3 * 5, 50);
      const auraScore = Math.floor(frequencyScore + spendScore);
      return {
        ...c,
        ltv: totalSpend,
        orderCount,
        last_order_at: lastOrder,
        aura_score: Math.max(auraScore, 10),
        segment: orderCount > 10 ? "VIP" : orderCount > 3 ? "REGULAR" : "NEW"
      };
    });
  }
