router2.get("/ledger", async (req, res) => {
  try {
    const { limit, accountId, date: date5, startDate, endDate, type, refType, searchQuery } = req.query;
    const restaurantId = req.restaurantId;
    const { prisma: prisma6 } = await Promise.resolve().then(() => (init_prisma(), prisma_exports));
    const dateFilter = {};
    if (startDate && endDate) {
      const { start } = await toUTCRange(restaurantId, startDate);
      const { end: actualEnd } = await toUTCRange(restaurantId, endDate);
      dateFilter.gte = start;
      dateFilter.lte = actualEnd;
    } else if (date5) {
      const { start, end } = await toUTCRange(restaurantId, date5);
      dateFilter.gte = start;
      dateFilter.lte = end;
    }
    const where = {
      chart_of_accounts: { restaurant_id: restaurantId },
      ...accountId ? { account_id: accountId } : {},
      ...Object.keys(dateFilter).length > 0 ? { journal_entries: { date: dateFilter } } : {},
      ...refType ? { journal_entries: { reference_type: refType } } : {},
      ...searchQuery ? {
        OR: [
          { description: { contains: searchQuery, mode: "insensitive" } },
          { journal_entries: { description: { contains: searchQuery, mode: "insensitive" } } }
        ]
      } : {}
    };
    const lines = await prisma6.journal_entry_lines.findMany({
      where,
      include: {
        journal_entries: {
          select: { reference_type: true, reference_id: true, description: true, date: true, created_at: true }
        },
        chart_of_accounts: { select: { code: true, name: true, type: true } }
      },
      orderBy: [{ journal_entries: { date: "asc" } }, { id: "asc" }],
      take: Number(limit) || 1e3
      // Increased limit for ledgers
    });
    let entries = lines.map((l) => ({
      id: l.id,
      created_at: l.journal_entries?.created_at || l.journal_entries?.date,
      reference_type: l.journal_entries?.reference_type,
      account_name: l.chart_of_accounts?.name,
      account_code: l.chart_of_accounts?.code,
      description: l.description || l.journal_entries?.description,
      amount: Math.abs(Number(l.debit) - Number(l.credit)),
      transaction_type: Number(l.debit) > 0 ? "DEBIT" : "CREDIT",
      debit: Number(l.debit),
      credit: Number(l.credit)
    }));
    if (type) {
      entries = entries.filter((e) => e.transaction_type === type);
    }
    let opening_balance = 0;
    let account_type = null;
    if (accountId) {
      const account = await prisma6.chart_of_accounts.findUnique({
        where: { id: accountId }
      });
      if (account) {
        account_type = account.type;
        if (dateFilter.gte) {
          const prevLines = await prisma6.journal_entry_lines.findMany({
            where: {
              account_id: accountId,
              journal_entries: { date: { lt: dateFilter.gte } }
            },
            select: { debit: true, credit: true }
          });
          const sumDebit = prevLines.reduce((acc, l) => acc + Number(l.debit), 0);
          const sumCredit = prevLines.reduce((acc, l) => acc + Number(l.credit), 0);
          const isDebitNormal = account.type === "ASSET" || account.type === "EXPENSE";
          opening_balance = isDebitNormal ? sumDebit - sumCredit : sumCredit - sumDebit;
        }
      }
    }
    return res.json({ success: true, entries, opening_balance, account_type });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});
