var import_express8 = require("express");
init_prisma();
var import_library15 = require("@prisma/client/runtime/library");
var router7 = (0, import_express8.Router)();
router7.get("/finance/summary", requireRole("MANAGER", "SUPER_ADMIN", "ADMIN"), async (req, res) => {
  try {
    const restaurantId = req.restaurantId;
    const { startDate, endDate } = req.query;
    if (!startDate || !endDate) {
      return res.status(400).json({ error: "startDate and endDate are required parameters" });
    }
    const { start } = await toUTCRange(restaurantId, startDate);
    const { end: rangeEnd } = await toUTCRange(restaurantId, endDate);
    const orders = await prisma.orders.findMany({
      where: {
        restaurant_id: restaurantId,
        status: { in: ["CLOSED", "DELIVERED"] },
        created_at: { gte: start, lte: rangeEnd }
      },
      select: { total: true, delivery_fee: true, discount: true, tax: true, service_charge: true }
    });
    let grossRevenue = new import_library15.Decimal(0);
    let netRevenue = new import_library15.Decimal(0);
    orders.forEach((o) => {
      const total = new import_library15.Decimal(o.total?.toString() || 0);
      const deliveryFee = new import_library15.Decimal(o.delivery_fee?.toString() || 0);
      const tax = new import_library15.Decimal(o.tax?.toString() || 0);
      const sc = new import_library15.Decimal(o.service_charge?.toString() || 0);
      const discount = new import_library15.Decimal(o.discount?.toString() || 0);
      const net3 = total.minus(tax).minus(sc).minus(deliveryFee);
      const gross = net3.plus(discount);
      grossRevenue = grossRevenue.plus(gross);
      netRevenue = netRevenue.plus(net3);
    });
    const inventoryJournals = await prisma.journal_entry_lines.findMany({
      where: {
        chart_of_accounts: {
          restaurant_id: restaurantId,
          code: "5000"
          // COGS Account code
        },
        journal_entries: {
          date: { gte: start, lte: rangeEnd }
        }
      }
    });
    let cogs = new import_library15.Decimal(0);
    inventoryJournals.forEach((j) => {
      const debit = new import_library15.Decimal(j.debit?.toString() || 0);
      const credit = new import_library15.Decimal(j.credit?.toString() || 0);
      cogs = cogs.plus(debit).minus(credit);
    });
    const expenseJournals = await prisma.journal_entry_lines.findMany({
      where: {
        chart_of_accounts: {
          restaurant_id: restaurantId,
          code: { startsWith: "6" }
        },
        journal_entries: {
          date: { gte: start, lte: rangeEnd }
        }
      }
    });
    let totalExpenses = new import_library15.Decimal(0);
    expenseJournals.forEach((j) => {
      const debit = new import_library15.Decimal(j.debit?.toString() || 0);
      const credit = new import_library15.Decimal(j.credit?.toString() || 0);
      totalExpenses = totalExpenses.plus(debit).minus(credit);
    });
    const grossMargin = netRevenue.minus(cogs);
    const netProfit = grossMargin.minus(totalExpenses);
    let cashPosition = new import_library15.Decimal(0);
    const cashJournals = await prisma.journal_entry_lines.findMany({
      where: {
        chart_of_accounts: { restaurant_id: restaurantId, code: "1000" }
      }
    });
    cashJournals.forEach((j) => {
      const debit = new import_library15.Decimal(j.debit?.toString() || 0);
      const credit = new import_library15.Decimal(j.credit?.toString() || 0);
      cashPosition = cashPosition.plus(debit).minus(credit);
    });
    res.json({
      grossRevenue,
      netRevenue,
      cogs,
      grossMargin,
      totalExpenses,
      netProfit,
      cashPosition
    });
  } catch (error49) {
    console.error("[ERROR] GET /api/analytics/finance/summary:", error49.message);
    res.status(500).json({ error: "Failed to fetch financial summary" });
  }
});
var analyticsRoutes_default = router7;

