app.get("/api/orders", async (req, res) => {
  const { restaurant_id } = req.query;
  try {
    const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1e3);
    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1e3);
    const orders = await prisma5.orders.findMany({
      where: {
        ...restaurant_id ? { restaurant_id: String(restaurant_id) } : {},
        OR: [
          // Always show active / non-terminal statuses
          { status: { notIn: ["CLOSED", "CANCELLED", "VOIDED", "DELIVERED"] } },
          // DELIVERED stays visible for 7 days (logistics settlement can span shifts)
          { status: "DELIVERED", created_at: { gte: sevenDaysAgo } },
          // CLOSED/CANCELLED/VOIDED visible 24h (register & activity log)
          { status: { in: ["CLOSED", "CANCELLED", "VOIDED"] }, created_at: { gte: twentyFourHoursAgo } }
        ]
      },
      include: {
        order_items: true,
        delivery_orders: true,
        takeaway_orders: true,
        dine_in_orders: true
      },
      orderBy: { created_at: "desc" },
      take: 500
    });
    res.json(orders);
  } catch (e) {
    console.error("\u274C Orders API Error:", e.message, e.code, e.meta);
    res.status(500).json({ error: e.message || "Failed to fetch orders", code: e.code });
  }
});
