app.post("/api/system/reset-environment", async (req, res) => {
  const { restaurantId } = req.body;
  if (!restaurantId) return res.status(400).json({ error: "Restaurant ID required" });
  console.log(`\u{1F9F9} RESET REQUEST FOR RESTAURANT: ${restaurantId}`);
  try {
    console.log("   - Deleting extension tables...");
    await prisma5.dine_in_orders.deleteMany({});
    await prisma5.takeaway_orders.deleteMany({});
    await prisma5.delivery_orders.deleteMany({});
    await prisma5.reservation_orders.deleteMany({});
    await prisma5.order_items.deleteMany({});
    console.log("   - Deleting financial records...");
    await prisma5.transactions.deleteMany({ where: { restaurant_id: restaurantId } });
    await prisma5.expenses.deleteMany({ where: { restaurant_id: restaurantId } });
    await prisma5.reservations.deleteMany({ where: { restaurant_id: restaurantId } });
    console.log("   - Deleting core orders...");
    await prisma5.orders.deleteMany({ where: { restaurant_id: restaurantId } });
    console.log("   - Resetting table statuses...");
    await prisma5.tables.updateMany({
      where: { restaurant_id: restaurantId },
      data: { status: "AVAILABLE", active_order_id: null, merge_id: null }
    });
    console.log("\u2705 RESET COMPLETE");
    io.emit("db_change", { table: "orders", eventType: "DELETE", id: "ALL" });
    io.emit("db_change", { table: "tables", eventType: "UPDATE", id: "ALL" });
    io.emit("db_change", { table: "transactions", eventType: "DELETE", id: "ALL" });
    res.json({ success: true, message: "Environment reset successfully. Database is now clean." });
  } catch (e) {
    console.error("Reset Failed:", e);
    res.status(500).json({ error: e.message });
  }
});
