app.post("/api/pairing/verify", pairingVerifyLimiter, async (req, res) => {
  const {
    restaurantId,
    codeId,
    code,
    deviceFingerprint,
    deviceName,
    userAgent,
    platform: platform2
  } = req.body;
  if (!code || !deviceFingerprint || !deviceName || !platform2) {
    return res.status(400).json({ error: "Missing required pairing fields" });
  }
  if (!/^[A-Z0-9]{6}$/.test(code)) {
    return res.status(400).json({ error: "Invalid code format" });
  }
  try {
    let finalRestaurantId = restaurantId;
    let finalCodeId = codeId;
    if (!finalCodeId || !finalRestaurantId) {
      const activeCode = await prisma5.pairing_codes.findFirst({
        where: {
          pairing_code: code,
          is_used: false,
          expires_at: { gt: /* @__PURE__ */ new Date() }
        }
      });
      if (!activeCode) {
        return res.status(404).json({ error: "Pairing code not found, expired, or already used" });
      }
      finalCodeId = activeCode.id;
      finalRestaurantId = activeCode.restaurant_id;
    }
    const pairingCode = await prisma5.pairing_codes.findFirst({
      where: {
        id: finalCodeId,
        restaurant_id: finalRestaurantId
      }
    });
    if (!pairingCode) {
      return res.status(404).json({ error: "Pairing code not found" });
    }
    const { authToken, deviceId } = await verifyPairingCode(
      finalRestaurantId,
      finalCodeId,
      code,
      deviceFingerprint,
      deviceName,
      userAgent,
      platform2
    );
    io.to(`restaurant:${finalRestaurantId}`).emit("device_change", {
      type: "device_registered",
      device_id: deviceId,
      device_name: deviceName,
      platform: platform2
    });
    res.json({
      success: true,
      device_id: deviceId,
      auth_token: authToken,
      // Send once to client, never store in DB
      message: "Device paired successfully",
      next_steps: "Save the auth_token securely on your device"
    });
  } catch (error49) {
    const errorMap = {
      "INVALID_CODE": 401,
      "CODE_EXPIRED": 410,
      "CODE_ALREADY_USED": 409,
      "TOO_MANY_ATTEMPTS": 429
    };
    const statusCode = errorMap[error49.message] || 500;
    console.error("[ERROR] /api/pairing/verify:", error49.message);
    res.status(statusCode).json({ error: error49.message || "Pairing verification failed" });
  }
});
